1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Step = { op: "quote"; items: Item[] };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_THRESHOLD_YEARS = 2;
13	const FOLLOWUP_DISCOUNT_RATE = 0.15;
14	
15	const COMPONENT_BLOCK_SIZE = 3;
16	const COMPONENT_BLOCK_PRICE = 60;
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const countByType = (items: Item[]): Record<string, number> => {
29	  const counts: Record<string, number> = {};
30	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
31	  return counts;
32	};
33	
34	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
35	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
36	
37	const lineItemPrice = (type: string, count: number): number =>
38	  qualifiesForComponentBlock(type, count)
39	    ? COMPONENT_BLOCK_PRICE
40	    : BASE_PREMIUM[type] * count;
41	
42	const sumBasePremiums = (items: Item[]): number =>
43	  Object.entries(countByType(items))
44	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
45	
46	const isCursed = (item: Item): boolean => item.cursed === true;
47	
48	const isHighlyEnchanted = (item: Item): boolean =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
50	
51	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
52	  applies ? BASE_PREMIUM[item.type] * rate : 0;
53	
54	const itemSurcharges = (items: Item[]): number =>
55	  items.reduce((sum, item) =>
56	    sum
57	    + surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE)
58	    + surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_RATE),
59	  0);
60	
61	const loyaltyDiscountFor = (customer: Customer, basePremium: number): number =>
62	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
63	    ? basePremium * LOYALTY_DISCOUNT_RATE
64	    : 0;
65	
66	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
67	
68	const followupDiscountFor = (stepIndex: number, basePremium: number): number =>
69	  isFollowupContract(stepIndex)
70	    ? basePremium * FOLLOWUP_DISCOUNT_RATE
71	    : 0;
72	
73	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
74	  const basePremium = sumBasePremiums(items);
75	  const surcharges = itemSurcharges(items);
76	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount = loyaltyDiscountFor(customer, basePremium);
78	  const followupDiscount = followupDiscountFor(stepIndex, basePremium);
79	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
80	};
81	
82	const validateItems = (items: Item[]): void => {
83	  for (const item of items) {
84	    if (!(item.type in BASE_PREMIUM)) {
85	      throw new Error(`Unknown item type: ${item.type}`);
86	    }
87	  }
88	};
89	
90	export const runScenario = (input: unknown): unknown => {
91	  const scenario = input as Scenario;
92	  const results = scenario.steps.map(({ items }, index) => {
93	    validateItems(items);
94	    return { premium: quotePremium(items, scenario.customer, index) };
95	  });
96	  return { results };
97	};
